import React, { useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { orderAPI, walletAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import './Orders.css';

// ✅ Matches backend orderStatus values: PLACED, CONFIRMED, DISPATCHED, DELIVERED, CANCELLED
const STATUS_CONFIG = {
  PLACED:     { label: 'Placed',     color: '#f59e0b', bg: 'rgba(245,158,11,0.12)'  },
  CONFIRMED:  { label: 'Confirmed',  color: '#3b82f6', bg: 'rgba(59,130,246,0.12)'  },
  DISPATCHED: { label: 'Dispatched', color: '#8b5cf6', bg: 'rgba(139,92,246,0.12)'  },
  DELIVERED:  { label: 'Delivered',  color: '#10b981', bg: 'rgba(16,185,129,0.12)'  },
  CANCELLED:  { label: 'Cancelled',  color: '#ef4444', bg: 'rgba(239,68,68,0.12)'   },
};

export default function Orders() {
  const [orders,       setOrders]       = useState([]);
  const [loading,      setLoading]      = useState(true);
  const [cancellingId, setCancellingId] = useState(null);
  const { isLoggedIn } = useAuth();
  const toast    = useToast();
  const navigate = useNavigate();

  useEffect(() => {
    if (!isLoggedIn()) {
      navigate('/login');
      return;
    }
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    try {
      setLoading(true);
      const res = await orderAPI.getMyOrders();
      setOrders(res.data || []);
    } catch (err) {
      toast.error('Failed to load orders');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = async (order) => {
    const isWalletPaid = order.modeOfPayment === 'WALLET';
    const confirmMsg = isWalletPaid
      ? `Cancel order #${order.orderId}? ₹${order.totalAmount?.toFixed(2)} will be refunded to your wallet.`
      : `Are you sure you want to cancel order #${order.orderId}?`;

    if (!window.confirm(confirmMsg)) return;

    setCancellingId(order.orderId);
    try {
      // Step 1 — Cancel the order on the backend
      await orderAPI.cancelOrder(order.orderId);

      // Step 2 — If paid via Wallet, refund the amount
      if (isWalletPaid) {
        try {
          await walletAPI.addMoney({
            amount:      order.totalAmount,
            description: `Refund for cancelled Order #${order.orderId}`,
          });
          toast.success(`Order cancelled! ₹${order.totalAmount?.toFixed(2)} refunded to your wallet. 💰`);
        } catch (refundErr) {
          // Order was cancelled but refund failed — show a warning
          toast.error(
            `Order cancelled, but wallet refund failed. Contact support with Order #${order.orderId}.`
          );
        }
      } else {
        toast.success('Order cancelled successfully');
      }

      fetchOrders();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Cannot cancel this order');
    } finally {
      setCancellingId(null);
    }
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return '—';
    return new Date(dateStr).toLocaleString('en-IN', {
      day: '2-digit', month: 'short', year: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  };

  const getPaymentLabel = (modeOfPayment) => {
    const labels = {
      COD:         '💵 Cash on Delivery',
      WALLET:      '💰 Wallet',
      UPI:         '📱 UPI',
      CREDIT_CARD: '💳 Credit Card',
      DEBIT_CARD:  '🏦 Debit Card',
      NET_BANKING: '🌐 Net Banking',
    };
    return labels[modeOfPayment] || modeOfPayment?.replace(/_/g, ' ');
  };

  // ── Loading ───────────────────────────────────────────────────────────────
  if (loading) {
    return (
      <div className="orders-page">
        <div className="orders-loading">
          <div className="spinner" />
          <p>Loading your orders…</p>
        </div>
      </div>
    );
  }

  // ── Empty ─────────────────────────────────────────────────────────────────
  if (orders.length === 0) {
    return (
      <div className="orders-page">
        <div className="orders-header">
          <h1>📦 My Orders</h1>
        </div>
        <div className="orders-empty">
          <div className="empty-icon">📭</div>
          <h2>No orders yet</h2>
          <p>When you place an order, it will appear here.</p>
          <Link to="/books" className="btn-gold-link">Browse Books →</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="orders-page">
      <div className="orders-header">
        <div>
          <h1>📦 My Orders</h1>
          <p className="orders-count">
            {orders.length} order{orders.length !== 1 ? 's' : ''} placed
          </p>
        </div>
      </div>

      <div className="orders-list">
        {orders.map((order) => {
          // ✅ Backend field: orderStatus (not status)
          const statusCfg = STATUS_CONFIG[order.orderStatus] || {
            label: order.orderStatus,
            color: '#888',
            bg: 'rgba(128,128,128,0.1)',
          };
          // ✅ Only PLACED orders can be cancelled (backend rule)
          const canCancel = order.orderStatus === 'PLACED';
          const isWalletPaid = order.modeOfPayment === 'WALLET';

          return (
            <div key={order.orderId} className="order-card">

              {/* Card Header */}
              <div className="order-card-header">
                <div className="order-meta">
                  <span className="order-id">Order #{order.orderId}</span>
                  {/* ✅ Backend field: orderDate (not createdAt) */}
                  <span className="order-date">{formatDate(order.orderDate)}</span>
                </div>
                <span
                  className="order-status-badge"
                  style={{ color: statusCfg.color, background: statusCfg.bg }}
                >
                  {statusCfg.label}
                </span>
              </div>

              {/* Items */}
              <div className="order-items-list">
                {(order.items || []).map((item, idx) => (
                  <div key={idx} className="order-item-row">
                    <div className="order-item-cover">
                      {(item.bookTitle || 'B')[0].toUpperCase()}
                    </div>
                    <div className="order-item-info">
                      <span className="order-item-title">{item.bookTitle}</span>
                      <span className="order-item-qty">
                        {item.bookAuthor && `by ${item.bookAuthor} · `}Qty: {item.quantity}
                      </span>
                    </div>
                    <span className="order-item-price">
                      ₹{(item.price * item.quantity).toFixed(2)}
                    </span>
                  </div>
                ))}
              </div>

              {/* Footer */}
              <div className="order-card-footer">
                {/* ✅ Backend fields: fullName, flatNumber, city, state, pincode */}
                <div className="order-address">
                  <span className="address-icon">📍</span>
                  <span className="address-text">
                    {[order.fullName, order.flatNumber, order.city, order.state, order.pincode]
                      .filter(Boolean)
                      .join(', ')}
                  </span>
                </div>

                <div className="order-footer-right">
                  {/* ✅ Backend field: modeOfPayment */}
                  <div className="order-payment-method">
                    {getPaymentLabel(order.modeOfPayment)}
                  </div>
                  <div className="order-total-amount">
                    Total: <strong>₹{order.totalAmount?.toFixed(2)}</strong>
                  </div>

                  {/* Cancel button — shows refund hint if wallet-paid */}
                  {canCancel && (
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4 }}>
                      <button
                        className="btn-cancel-order"
                        onClick={() => handleCancel(order)}
                        disabled={cancellingId === order.orderId}
                      >
                        {cancellingId === order.orderId ? 'Cancelling…' : 'Cancel Order'}
                      </button>
                      {isWalletPaid && (
                        <span style={{ fontSize: '0.73rem', color: '#10b981' }}>
                          💰 ₹{order.totalAmount?.toFixed(2)} will be refunded to wallet
                        </span>
                      )}
                    </div>
                  )}
                </div>
              </div>

            </div>
          );
        })}
      </div>
    </div>
  );
}
